UPDATE notes SET body_json = $tiptap${"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Volume 1 — Manifesto e Filosofia"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 2 — Arquitetura do LifeOS"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 3 — Modelagem de Dados (Life Graph)"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 4 — IA, Memória e Agentes"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 5 — Módulos do Sistema"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 6 — UX e Fluxos"}]},{"type":"paragraph","content":[{"type":"text","text":"Volume 7 — Roadmap e Estratégia"}]},{"type":"paragraph"},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"MOS Core (o núcleo do sistema)"}]},{"type":"paragraph","content":[{"type":"text","text":"MOS DNA (como o sistema aprende quem é o usuário)"}]},{"type":"paragraph","content":[{"type":"text","text":"Life Graph em nível de banco de dados"}]},{"type":"paragraph","content":[{"type":"text","text":"Context Engine detalhado"}]},{"type":"paragraph","content":[{"type":"text","text":"Memory Engine (memória episódica, semântica e operacional)"}]},{"type":"paragraph","content":[{"type":"text","text":"Decision Engine (como a IA toma decisões)"}]},{"type":"paragraph","content":[{"type":"text","text":"Recommendation Engine"}]},{"type":"paragraph","content":[{"type":"text","text":"Insight Engine"}]},{"type":"paragraph","content":[{"type":"text","text":"Universal Event Model"}]},{"type":"paragraph","content":[{"type":"text","text":"Mission System"}]},{"type":"paragraph","content":[{"type":"text","text":"Resource System"}]},{"type":"paragraph","content":[{"type":"text","text":"Relationship Graph"}]},{"type":"paragraph","content":[{"type":"text","text":"Digital Twin (o modelo digital do usuário)"}]},{"type":"paragraph","content":[{"type":"text","text":"MOS Language (a linguagem interna que a IA usa para raciocinar)"}]},{"type":"paragraph","content":[{"type":"text","text":"MOS Constitution (os princípios imutáveis)"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Ele deve ser organizado como o cérebro humano."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Por exemplo."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"O cérebro possui:"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"memória;"}]},{"type":"paragraph","content":[{"type":"text","text":"atenção;"}]},{"type":"paragraph","content":[{"type":"text","text":"percepção;"}]},{"type":"paragraph","content":[{"type":"text","text":"linguagem;"}]},{"type":"paragraph","content":[{"type":"text","text":"planejamento;"}]},{"type":"paragraph","content":[{"type":"text","text":"tomada de decisão;"}]},{"type":"paragraph","content":[{"type":"text","text":"aprendizagem."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"O MOS também deveria possuir exatamente essas capacidades."}]},{"type":"paragraph"},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"capítulos como:"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Como o MOS percebe o mundo."}]},{"type":"paragraph","content":[{"type":"text","text":"Como cria memória."}]},{"type":"paragraph","content":[{"type":"text","text":"Como esquece."}]},{"type":"paragraph","content":[{"type":"text","text":"Como aprende."}]},{"type":"paragraph","content":[{"type":"text","text":"Como identifica padrões."}]},{"type":"paragraph","content":[{"type":"text","text":"Como cria contexto."}]},{"type":"paragraph","content":[{"type":"text","text":"Como toma decisões."}]},{"type":"paragraph","content":[{"type":"text","text":"Como gera prioridades."}]},{"type":"paragraph","content":[{"type":"text","text":"Como conversa."}]},{"type":"paragraph","content":[{"type":"text","text":"Como cria autonomia."}]},{"type":"paragraph","content":[{"type":"text","text":"Como se adapta ao usuário."}]},{"type":"paragraph"},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"O MOS deve possuir um DNA."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Esse DNA é uma árvore."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Vision"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Principles"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Concepts"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Architecture"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Engines"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Domains"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Features"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"↓"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Screens"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Nunca o contrário."}]}]}$tiptap$::jsonb WHERE id = '2e477ab2-2ab9-4758-af17-714b249e62e2';

